	// --- Check for target parity = ODD (1) ---
	canBeOdd := true
	for i := 0; i < n; i++ {
		isPossible := false
		// Option 1: nums2[i] = nums1[i]
		if nums1[i]%2 != 0 { // nums1[i] is odd
			isPossible = true
