		// Option 2: nums2[i] = nums1[i] - nums1[j], j != i
		if !isPossible {
			for j := 0; j < n; j++ {
				if i == j {
					continue
				}
				// (nums1[i] - nums1[j]) is odd iff nums1[i] and nums1[j] have different parities
				if (nums1[i]%2) != (nums1[j]%2) {
					isPossible = true
					break
				}
			}
		}
		if !isPossible {
			canBeOdd = false
			break
		}
	}

	return canBeOdd
